using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var baseUrl = Environment.GetEnvironmentVariable("OPENAI_BASE_URL");

// --- Prompt for topic ---
var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Shared state ---
var notebook = new List<string>();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.Add("User-Agent", "ResearchAgent/1.0");

// --- Define tools ---
var tools = new AIFunction[]
{
    AIFunctionFactory.Create(SearchWeb, "search_web",
        "Search the web for information on a query. Returns relevant text snippets."),
    AIFunctionFactory.Create(TakeNote, "take_note",
        "Save an important finding or insight to the notebook for later summarization."),
    AIFunctionFactory.Create(ReadNotes, "read_notes",
        "Read all notes taken so far to review findings before writing a summary."),
};

// --- Build chat client with automatic function invocation ---
var openAiOptions = new OpenAIClientOptions();
if (baseUrl is not null)
    openAiOptions.Endpoint = new Uri(baseUrl);

var openAIClient = new OpenAIClient(new System.ClientModel.ApiKeyCredential(apiKey), openAiOptions);
var innerClient = new OpenAIChatClient(openAIClient.GetChatClient(modelName));

IChatClient client = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation()
    .Build();

// --- Agent system prompt ---
const string systemPrompt = """
    You are a research agent. Your goal is to thoroughly research the given topic.

    Follow this process:
    1. Search the web for information using different search queries (at least 3).
    2. After each search, take notes on the most important findings.
    3. Once you have gathered enough information, read your notes.
    4. Provide a comprehensive final summary with these sections:
       - **Overview** – what the topic is about
       - **Key Findings** – the most important facts and insights
       - **Conclusion** – a brief wrap-up

    Tips:
    - Vary your search queries to cover different angles of the topic.
    - Always take notes before moving on to the next search.
    - Be thorough but concise in your final summary.
    """;

var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User, $"Research the following topic thoroughly: {topic}"),
};

// --- Run the agent ---
var response = await client.GetResponseAsync(messages, new ChatOptions { Tools = tools });

Console.WriteLine("\n" + new string('═', 60));
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine(new string('═', 60) + "\n");
Console.WriteLine(response.Text);
Console.WriteLine($"\n📝 Total notes taken during research: {notebook.Count}");

// ═══════════════════════════════════════════════════════════
// Tool implementations
// ═══════════════════════════════════════════════════════════

async Task<string> SearchWeb(
    [Description("The search query")] string query)
{
    Console.WriteLine($"  🌐 Searching: \"{query}\"");
    try
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
        var json = await httpClient.GetStringAsync(url);
        var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;
        var snippets = new List<string>();

        if (root.TryGetProperty("Abstract", out var abs)
            && abs.GetString() is { Length: > 0 } abstractText)
        {
            snippets.Add($"[Summary] {abstractText}");
        }

        if (root.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var item in topics.EnumerateArray().Take(8))
            {
                if (item.TryGetProperty("Text", out var text)
                    && text.GetString() is { Length: > 0 } t)
                {
                    snippets.Add(t);
                }
                // Handle sub-topics (grouped items)
                else if (item.TryGetProperty("Topics", out var subTopics))
                {
                    foreach (var sub in subTopics.EnumerateArray().Take(3))
                    {
                        if (sub.TryGetProperty("Text", out var subText)
                            && subText.GetString() is { Length: > 0 } st)
                        {
                            snippets.Add(st);
                        }
                    }
                }
            }
        }

        if (snippets.Count == 0)
            return "No results found. Try rephrasing your query or using different keywords.";

        Console.WriteLine($"       Found {snippets.Count} snippet(s)");
        return string.Join("\n\n", snippets);
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}. Try a different query.";
    }
}

string TakeNote(
    [Description("The note content to save")] string note)
{
    notebook.Add(note);
    Console.WriteLine($"  📝 Note #{notebook.Count} saved ({note.Length} chars)");
    return $"Note #{notebook.Count} saved. You now have {notebook.Count} note(s).";
}

string ReadNotes()
{
    if (notebook.Count == 0)
        return "No notes taken yet. Use the take_note tool to save findings first.";

    Console.WriteLine($"  📖 Reading {notebook.Count} note(s)");
    var formatted = notebook.Select((n, i) => $"--- Note {i + 1} ---\n{n}");
    return string.Join("\n\n", formatted);
}

static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(input) ? "quantum computing" : input;
}

